// Fetch conversations abandonadas que necesitan re-engagement
const SUPABASE_URL = $env.N8N_SUPABASE_URL || 'https://inhyrrjidhzrbqecnptn.supabase.co';
const SERVICE_KEY = $env.N8N_SUPABASE_SERVICE_KEY;

let conversations;
try {
  conversations = await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/rpc/get_conversations_to_reengage',
    headers: {
      'apikey': SERVICE_KEY,
      'Authorization': 'Bearer ' + SERVICE_KEY,
      'Content-Type': 'application/json'
    },
    body: {},
    json: true
  });
} catch(e) {
  console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'FETCH_ERROR', error: e.message }));
  conversations = [];
}

if (!Array.isArray(conversations) || conversations.length === 0) {
  console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'NO_CONVERSATIONS' }));
  return [{ json: { no_conversations: true, count: 0 } }];
}

console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'CONVERSATIONS_FOUND', count: conversations.length }));

return conversations.map(c => ({ json: c }));

// Para cada conversación abandonada:
// - R1: buscar slots ofrecidos en Chatwoot y re-presentarlos
// - R2: mensaje de último intento (template-style)

const item = $input.first().json;
const CHATWOOT_BASE = 'https://chat.redsolucionesti.com';
const CHATWOOT_TOKEN = item.chatwoot_api_token || 'yypAwZDH2dV3crfbqJqWCgj1';
const account_id = item.chatwoot_account_id || 2;
const conversation_id = item.chatwoot_conversation_id;
const reminder_type = item.reminder_type; // 'R1' | 'R2'
const patient_name = item.patient_name || '';
const first_name = patient_name.split(' ')[0] || '';
const greeting = first_name ? ('Hola ' + first_name + '! 👋') : 'Hola! 👋';

let message_content = '';

if (reminder_type === 'R1') {
  // Intentar recuperar los slots ofrecidos
  let slots = [];
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: CHATWOOT_BASE + '/api/v1/accounts/' + account_id + '/conversations/' + conversation_id + '/messages',
      headers: { 'api_access_token': CHATWOOT_TOKEN }
    });
    const messages = (resp.payload || []).reverse();
    const slotNote = messages.find(m =>
      m.private &&
      typeof m.content === 'string' &&
      m.content.startsWith('SOFIA_SLOTS:')
    );
    if (slotNote) {
      const raw = slotNote.content.replace('SOFIA_SLOTS:', '');
      const parsed = JSON.parse(raw);
      slots = Array.isArray(parsed) ? parsed : (parsed.slots || []);
    }
  } catch(e) {
    console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'SLOTS_FETCH_ERROR', conv: conversation_id, error: e.message }));
  }

  if (slots.length > 0) {
    // Re-ofrecer los mismos slots
    const slot_lines = slots.map((s, i) => {
      const label = s.label || s.display || (s.date + ' ' + s.time);
      return '⏰ Opción ' + (i + 1) + ': ' + label;
    }).join('\n');

    message_content = greeting + '\n\n' +
      'Notamos que no terminaste de elegir tu horario para tu cita 🦷\n\n' +
      'Aquí están las opciones que tenías disponibles:\n' +
      slot_lines + '\n\n' +
      'Responde con el número de tu opción preferida y listo 😊';
  } else {
    // Sin slots guardados — mensaje genérico
    message_content = greeting + '\n\n' +
      'Notamos que no terminaste de agendar tu cita. ¿Pudimos ayudarte? 🦷\n\n' +
      'Si quieres, dime qué día te viene mejor y te busco los horarios disponibles 😊';
  }

} else {
  // R2: mensaje de último intento, más breve
  message_content = greeting + '\n\n' +
    '⏰ Seguimos aquí si necesitas agendar tu cita dental.\n\n' +
    'Tenemos horarios disponibles esta semana. ¿Te agendamos ahora?\n\n' +
    'Si prefieres hablar con un asesor, también puedes escribirnos directamente 😊';
}

console.log(JSON.stringify({
  ts: new Date().toISOString(),
  event: 'MESSAGE_BUILT',
  conv: conversation_id,
  type: reminder_type,
  len: message_content.length
}));

return [{
  json: {
    ...item,
    message_content: message_content
  }
}];
